def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.enum.text import PP_ALIGN
    prs = Presentation(modified_ppt_path)
    slide = None
    # Find slide 4 (zero-based index)
    try:
        slide = prs.slides[3]
    except IndexError:
        return ("Slide 4 does not exist in the presentation.", 0.0)
    # Try to find the title shape
    title_shape = None
    for shape in slide.shapes:
        if shape.has_text_frame and shape.text_frame and shape.text_frame.text.strip():
            # Heuristic: check if it's the title placeholder
            if shape.is_placeholder and shape.placeholder_format.type == 1: # TITLE
                title_shape = shape
                break
    if not title_shape:
        # Fallback: find the largest textbox on slide
        max_area = 0
        for shape in slide.shapes:
            if shape.has_text_frame and shape.text_frame.text.strip():
                area = shape.width * shape.height
                if area > max_area:
                    max_area = area
                    title_shape = shape
    if not title_shape:
        return ("No title text box found on slide 4.", 0.0)
    para = title_shape.text_frame.paragraphs[0]
    if para.alignment == PP_ALIGN.CENTER:
        return ("Title text is center aligned on slide 4.", 1.0)
    else:
        return ("Title text is not center aligned on slide 4.", 0.0)

